UPDATE books SET audio_preferences='{\"model\":\"kokoro\",\"voice\":\"af_heart\"}', updated_at=strftime('%Y-%m-%dT%H:%M:%S','now') WHERE id=19;

INSERT INTO audiobook_tasks (book_id, chapter_id, scope, voice, model, speed, status, progress, attempt_number, inserted_at, updated_at)
