INSERT INTO oban_jobs (state, queue, worker, args, max_attempts)
SELECT 'available', 'tts', 'ReadaloudAudiobook.GenerateJob', json_object('task_id', id), 3
FROM audiobook_tasks WHERE book_id=19 ORDER BY id;

SELECT 'queued audiobook tasks: ' || count(*) FROM audiobook_tasks WHERE book_id=19;
SELECT 'queued oban jobs: ' || count(*) FROM oban_jobs WHERE worker='ReadaloudAudiobook.GenerateJob' AND state IN ('available','executing','scheduled') AND args LIKE '%task_id%';
SQL"

