const s = document.createElement('script'); s.textContent = `
(function(){
  let tries = 0;
  const id = setInterval(() => {
    tries++;
    if (window.liveSocket?.hooks?.AudioPlayer && !window.__patched) {
      window.__patched = true;
      window.__hookLog = [];
      const orig = window.liveSocket.hooks.AudioPlayer.mounted;
      window.liveSocket.hooks.AudioPlayer.mounted = function() {
        window.__hookLog.push({step: 'enter', tries: tries, hasAudio: !!document.getElementById('audio-element'), dataAudio: this.el?.dataset?.audioUrl?.length});
        try { orig.call(this); window.__hookLog.push({step: 'ok', src: this.audio?.src?.substring(0,80)}); } catch(e) { window.__hookLog.push({step: 'err', msg: e.message, stack: e.stack?.split('\\n').slice(0,3).join('|')}); }
      };
      clearInterval(id);
    }
    if (tries > 100) clearInterval(id);
  }, 20);
})();
`; document.head.appendChild(s); 'injected'

