1	export const AudioPlayer = {
2		mounted() {
3			this.audio = document.getElementById("audio-element");
4			this.playPauseBtn = document.getElementById("play-pause-btn");
5			this.timeDisplay = document.getElementById("time-display");
6			this.textContainer = document.getElementById("chapter-text");
7			this.resyncBtn = document.getElementById("resync-btn");
8			this.timings = [];
9			this.currentWordIndex = -1;
10			this.autoScrollPaused = false;
11			this.isAutoScrolling = false;
12	
13			// Load persisted state
14			const collapsed =
15				localStorage.getItem("readaloud-player-collapsed") === "true";
16			if (collapsed) this.el.classList.add("collapsed");
17	
18			const savedSpeed = parseFloat(
19				localStorage.getItem("readaloud-playback-speed") || "1",
20			);
21			this.audio.playbackRate = savedSpeed;
22	
23			const savedVolume = parseFloat(
24				localStorage.getItem("readaloud-volume") || "1",
25			);
26			this.audio.volume = savedVolume;
27	
28			// Update volume slider UI
29			const volSlider = this.el.querySelector("[data-volume-slider]");
30			if (volSlider) volSlider.value = savedVolume;
31	
32			// Update speed button active state
33			this.updateSpeedButtons(savedSpeed);
34	
35			// Load audio
36			this.audio.src = this.el.dataset.audioUrl;
37	
38			// Show duration as soon as metadata is available (don't wait for first
39			// timeupdate, which only fires once playback starts).
40			this.audio.addEventListener("loadedmetadata", () =>
41				this.updateTimeDisplay(),
42			);
43			this.audio.addEventListener("durationchange", () =>
44				this.updateTimeDisplay(),
45			);
46	
47			// Load word-level timings
48			fetch(this.el.dataset.timingsUrl)
49				.then((r) => r.json())
50				.then((data) => {
51					this.timings = data.timings || [];
52					// Set up click-to-seek on word spans
53					this.setupWordClickListeners();
54				});
55	
56			// Restore position
57			const initialMs = parseInt(this.el.dataset.initialPosition || "0", 10);
58			if (initialMs > 0) {
59				this.audio.addEventListener(
60					"loadedmetadata",
61					() => {
62						this.audio.currentTime = initialMs / 1000;
63					},
64					{ once: true },
65				);
66			}
67	
68			// Play/pause button
69			this.playPauseBtn.addEventListener("click", () => this.togglePlayback());
70	
71			// Skip back/forward buttons
72			const skipBack = this.el.querySelector("[data-skip-back]");
73			const skipFwd = this.el.querySelector("[data-skip-forward]");
74			if (skipBack)
75				skipBack.addEventListener("click", () => {
76					this.audio.currentTime = Math.max(0, this.audio.currentTime - 10);
77				});
78			if (skipFwd)
79				skipFwd.addEventListener("click", () => {
80					this.audio.currentTime = Math.min(
81						this.audio.duration || Infinity,
82						this.audio.currentTime + 10,
83					);
84				});
85	
86			// Collapse toggle
87			const collapseToggle = this.el.querySelector("[data-collapse-toggle]");
88			if (collapseToggle) {
89				collapseToggle.addEventListener("click", () => {
90					const isCollapsed = this.el.classList.toggle("collapsed");
91					localStorage.setItem("readaloud-player-collapsed", isCollapsed);
92				});
93			}
94	
95			// Speed buttons
96			this.el.querySelectorAll("[data-speed]").forEach((btn) => {
97				btn.addEventListener("click", () => {
98					const speed = parseFloat(btn.dataset.speed);
99					this.setSpeed(speed);
100				});
101			});
102	
103			// Volume slider
104			if (volSlider) {
105				volSlider.addEventListener("input", () => {
106					const vol = parseFloat(volSlider.value);
107					this.audio.volume = vol;
108					localStorage.setItem("readaloud-volume", vol);
109				});
110			}
111	
112			// Scrubber: main + mini (store window listeners for cleanup)
113			this._scrubberCleanups = [];
114			const scrubber = this.el.querySelector("[data-scrubber]");
115			if (scrubber) {
116				this.setupScrubber(scrubber);
117			}
118	
119			const scrubberMini = this.el.querySelector("[data-scrubber-mini]");
120			if (scrubberMini) {
121				this.setupScrubber(scrubberMini);
122			}
123	
124			// Fallback: old progress-bar ID if present
125			const progressBar = document.getElementById("progress-bar");
126			if (progressBar && !scrubber && !scrubberMini) {
127				progressBar.addEventListener("click", (e) => {
128					const rect = progressBar.getBoundingClientRect();
129					const pct = (e.clientX - rect.left) / rect.width;
130					this.audio.currentTime = pct * this.audio.duration;
131				});
132			}
133	
134			// Time update: progress + time display + position reporting (low frequency)
135			this.audio.addEventListener("timeupdate", () => {
136				if (this.audio.duration) {
137					const pct = (this.audio.currentTime / this.audio.duration) * 100;
138	
139					// Update scrubber fills (main + mini)
140					const fill =
141						this.el.querySelector("[data-progress-fill]") ||
142						document.getElementById("progress-fill");
143					if (fill) fill.style.width = `${pct}%`;
144					const fillMini = this.el.querySelector("[data-progress-fill-mini]");
145					if (fillMini) fillMini.style.width = `${pct}%`;
146	
147					this.updateTimeDisplay();
148	
149					// Report position (throttled: every ~5s of audio time)
150					const nowMs = Math.round(this.audio.currentTime * 1000);
151					if (
152						!this._lastReportedMs ||
153						Math.abs(nowMs - this._lastReportedMs) >= 5000
154					) {
155						this._lastReportedMs = nowMs;
156						this.pushEvent("audio_position", { position_ms: nowMs });
157					}
158				}
159			});
160	
161			// High-frequency word highlighting via requestAnimationFrame (60fps)
162			this._rafId = null;
163			this._startHighlightLoop = () => {
164				const tick = () => {
165					if (this.audio && !this.audio.paused) {
166						this.highlightWord(this.audio.currentTime * 1000);
167						this._rafId = requestAnimationFrame(tick);
168					}
169				};
170				this._rafId = requestAnimationFrame(tick);
171			};
172			this._stopHighlightLoop = () => {
173				if (this._rafId) {
174					cancelAnimationFrame(this._rafId);
175					this._rafId = null;
176				}
177			};
178			this.audio.addEventListener("play", this._startHighlightLoop);
179			this.audio.addEventListener("pause", this._stopHighlightLoop);
180			this.audio.addEventListener("ended", this._stopHighlightLoop);
181	
182			// Play/pause state
183			this.audio.addEventListener("play", () => {
184				this.playPauseBtn.innerHTML = "&#10074;&#10074;";
185				if (this.textContainer) this.textContainer.dataset.audioPlaying = "true";
186			});
187	
188			this.audio.addEventListener("pause", () => {
189				this.playPauseBtn.innerHTML = "&#9654;";
190				if (this.textContainer) this.textContainer.dataset.audioPlaying = "false";
191				this.pushEvent("audio_position", {
192					position_ms: Math.round(this.audio.currentTime * 1000),
193				});
194			});
195	
196			// Auto-advance
197			this.audio.addEventListener("ended", () => {
198				const settings = this.loadReaderSettings();
199				if (settings.autoNextChapter) {
200					this.pushEvent("next_chapter", {});
201				}
202			});
203	
204			// Re-sync button
205			if (this.resyncBtn) {
206				this.resyncBtn.addEventListener("click", () => {
207					this.autoScrollPaused = false;
208					this.resyncBtn.classList.add("hidden");
209					// Force scroll to current word
210					if (this.currentWordIndex >= 0 && this.textContainer) {
211						const el = this.textContainer.querySelector(
212							`[data-word-index="${this.currentWordIndex}"]`,
213						);
214						if (el) el.scrollIntoView({ behavior: "smooth", block: "center" });
215					}
216				});
217			}
218	
219			// Manual scroll detection from ScrollTracker
220			this._manualScrollHandler = () => {
221				if (!this.audio.paused && !this.isAutoScrolling) {
222					this.autoScrollPaused = true;
223					if (this.resyncBtn) this.resyncBtn.classList.remove("hidden");
224				}
225			};
226			window.addEventListener("manual-scroll", this._manualScrollHandler);
227	
228			// Auto-scroll lifecycle events
229			this._autoScrollStartHandler = () => {
230				this.isAutoScrolling = true;
231			};
232			this._autoScrollEndHandler = () => {
233				this.isAutoScrolling = false;
